const SectorPill = memo(({ name, imgSrc }: any) => (
    <div className="flex flex-shrink-0 items-center gap-4 bg-white rounded-full py-2.5 pl-2.5 pr-6 shadow-sm border border-gray-100 cursor-default hover:shadow-xl hover:shadow-brand-orange/10 hover:border-brand-orange/30 transition-all duration-300 hover:-translate-y-1 gpu-accel">
