import React, { useState, useMemo, useCallback, useEffect, memo } from 'react';
import { useTranslation } from 'react-i18next';
import { ChevronDown } from 'lucide-react';
import { HERO_SLIDES } from '../../../lib/constants';

const SLIDE_DURATION_MS = 6000; 

const Hero: React.FC = () => {
  const { t } = useTranslation();
  const [currentIndex, setCurrentIndex] = useState(0);

  const slides = useMemo(() => HERO_SLIDES.map(slide => ({
    ...slide,
    title: t(`hero.slides.${slide.id}.title`),
    subtitle: t(`hero.slides.${slide.id}.subtitle`),
    buttonText: t(`hero.slides.${slide.id}.buttonText`)
  })), [t]);

  const nextSlide = useCallback(() => {
    setCurrentIndex(prev => (prev === slides.length - 1 ? 0 : prev + 1));
  }, [slides.length]);

  useEffect(() => {
    const timer = setInterval(nextSlide, SLIDE_DURATION_MS);
    return () => clearInterval(timer);
  }, [nextSlide]);

  return (
    <section className="relative h-[75vh] min-h-[500px] overflow-hidden bg-brand-blue-dark gpu-accel">
        <style>{`
            @keyframes kenburns {
                from { transform: scale(1) translate3d(0,0,0); }
                to { transform: scale(1.1) translate3d(0,0,0); }
            }
            .animate-kb { animation: kenburns ${SLIDE_DURATION_MS}ms linear infinite alternate; will-change: transform; }
        `}</style>

        {slides.map((slide, index) => (
          <div 
            key={index}
            className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${index === currentIndex ? 'opacity-100' : 'opacity-0'}`}
          >
            <img
                src={slide.imageUrl}
                alt=""
                fetchPriority={index === 0 ? "high" : "low"}
                loading={index === 0 ? "eager" : "lazy"}
                decoding="async"
                className={`w-full h-full object-cover ${index === currentIndex ? 'animate-kb' : ''}`}
            />
            <div className="absolute inset-0 bg-gradient-to-r from-brand-blue-dark via-brand-blue-dark/50 to-transparent"></div>
          </div>
        ))}

        <div className="relative z-10 h-full flex items-center">
            <div className="container mx-auto px-6 sm:px-12 lg:px-24 max-w-[1920px]">
                <div className="max-w-3xl">
                    <h1 className="text-3xl md:text-6xl font-bold text-white mb-6 drop-shadow-lg leading-tight animate-slide-in">
                        {slides[currentIndex].title}
                    </h1>
                    <p className="text-lg md:text-xl text-gray-200 mb-10 drop-shadow-md animate-slide-in" style={{ animationDelay: '150ms' }}>
                        {slides[currentIndex].subtitle}
                    </p>
                    <button className="bg-brand-orange text-white font-bold py-4 px-10 rounded-full hover:bg-brand-orange-dark transition-all transform hover:scale-105 shadow-xl uppercase tracking-widest text-sm animate-slide-in" style={{ animationDelay: '300ms' }}>
                        {slides[currentIndex].buttonText}
                    </button>
                </div>
            </div>
        </div>

        {/* Indicators */}
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-20 flex gap-3">
            {slides.map((_, idx) => (
                <button 
                    key={idx} 
                    onClick={() => setCurrentIndex(idx)}
                    className={`h-1 transition-all duration-300 rounded-full ${idx === currentIndex ? 'w-10 bg-brand-orange' : 'w-4 bg-white/30'}`}
                    aria-label={`Slide ${idx + 1}`}
                />
            ))}
        </div>
    </section>
  );
};

export default memo(Hero);

