        text: t(`header.navLinks.${link.key}`),
        href: link.href
    })), [t]);

    const isLinkActive = useCallback((href: string) => 
        currentRoute === href || (currentRoute.startsWith(href) && href !== '#/'), 
    [currentRoute]);

    return (
        <>
            <header className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ease-out gpu-accel ${isScrolled ? 'bg-brand-blue-dark/95 backdrop-blur-md shadow-2xl border-b-2 border-brand-orange' : 'bg-brand-blue-dark border-b border-white/5'}`}>
